import React, { useState } from "react";
import { ChevronLeft, Banknote, Lock } from "lucide-react";
import { useCurrency } from "../context/CurrencyContext";

export default function DepositScreen({
  onBack,
  onConfirm,
  darkMode,
  openScreen,
}) {
  const { formatAmount } = useCurrency();

  const [amount, setAmount] = useState("");
  const [duration, setDuration] = useState(3);
  const [sourceAccount, setSourceAccount] = useState("Access Bank - **** 1234");

  const numericAmount = Number(amount);
  const isValidAmount = numericAmount > 0 && !Number.isNaN(numericAmount);

  const calculateWithdrawalDate = (months) => {
    const date = new Date();
    date.setMonth(date.getMonth() + months);
    return date;
  };

  const handleConfirm = () => {
    if (!isValidAmount) return;

    const startDate = new Date();
    const withdrawalDate = calculateWithdrawalDate(duration);

    onConfirm({
      amount: numericAmount,
      durationMonths: duration,
      startDate: startDate.toISOString(),
      withdrawalDate: withdrawalDate.toISOString(),
      source: sourceAccount,
    });
  };

  // Dark mode classes
  const bgClass = darkMode ? "bg-gray-900 text-white" : "bg-white text-gray-900";
  const inputBgClass = darkMode ? "bg-gray-800 text-white border-gray-700" : "bg-gray-50 border-gray-100";
  const selectBgClass = darkMode ? "bg-gray-800 text-white border-gray-700" : "bg-gray-50 border-gray-100";
  const buttonDurationActive = "bg-[#00875A] text-white";
  const buttonDurationInactive = darkMode ? "bg-gray-800 text-gray-300" : "bg-gray-100 text-gray-700";
  const textGrayClass = darkMode ? "text-gray-300" : "text-gray-700";

  return (
    <div className={`flex flex-col animate-in slide-in-from-right duration-300 h-full ${bgClass}`}>

      {/* Header */}
      <div className={`flex items-center gap-3 px-6 py-4 sticky top-0 z-10 ${darkMode ? "bg-gray-900 border-b border-gray-700" : "bg-white border-b border-gray-50"}`}>
        <button
          onClick={onBack}
          className={`p-2 rounded-full transition-colors ${darkMode ? "hover:bg-gray-800" : "hover:bg-gray-100"}`}
        >
          <ChevronLeft className="w-6 h-6" />
        </button>
        <h1 className="text-xl font-bold">Lock Your Savings</h1>
      </div>

      {/* Content */}
      <div className="p-6 flex-1">

        {/* Lock Info */}
        <div className={`p-6 rounded-[2.5rem] mb-8 border ${darkMode ? "bg-gray-800 border-gray-700 text-gray-300" : "bg-emerald-50 border-emerald-100 text-emerald-700"}`}>
          <div className="flex items-center gap-2 mb-2 font-bold">
            <Lock size={18} />
            Locked Savings
          </div>
          <p className="text-sm">
            Your money will be locked until the selected withdrawal date.
            Early withdrawal is not allowed.
          </p>
        </div>

        {/* Amount */}
        <div className="space-y-2 mb-6">
          <label className={`text-sm font-bold ml-1 ${textGrayClass}`}>Amount to Save</label>
          <div className="relative">
            <Banknote className={`absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 ${textGrayClass}`} />
            <input
              type="number"
              inputMode="numeric"
              value={amount}
              onChange={(e) => setAmount(e.target.value)}
              placeholder={formatAmount(0)}
              className={`w-full p-4 pl-12 rounded-2xl outline-none focus:border-[#00875A] text-lg font-bold ${inputBgClass}`}
            />
          </div>
        </div>

        {/* Duration */}
        <div className="space-y-3 mb-6">
          <label className={`text-sm font-bold ml-1 ${textGrayClass}`}>Savings Duration</label>
          <div className="grid grid-cols-3 gap-3">
            {[3, 6, 12].map((m) => (
              <button
                key={m}
                onClick={() => setDuration(m)}
                className={`py-3 rounded-xl font-bold transition ${
                  duration === m ? buttonDurationActive : buttonDurationInactive
                }`}
              >
                {m} months
              </button>
            ))}
          </div>
        </div>

        {/* Source Account */}
        <div className="space-y-2">
          <label className={`text-sm font-bold ml-1 ${textGrayClass}`}>Payment Source</label>
          <select
            value={sourceAccount}
            onChange={(e) => setSourceAccount(e.target.value)}
            className={`w-full p-4 rounded-2xl outline-none font-medium ${selectBgClass}`}
          >
            <option>Access Bank - **** 1234</option>
            <option>GTBank - **** 5678</option>
            <option value="add-new">Add New Bank Card</option>
          </select>
        </div>
      </div>

      {/* Add Bank */}
      <p className={`text-center text-sm mb-4 ${darkMode ? "text-gray-400" : "text-gray-400"}`}>
        Don&apos;t see your card?{" "}
        <button
          className="text-[#00875A] font-black cursor-pointer"
          onClick={() => openScreen && openScreen("AddPaymentSource")}
        >
          Add New Card
        </button>
      </p>

      {/* Confirm */}
      <div className="pb-10 flex justify-center">
        <button
          onClick={handleConfirm}
          disabled={!isValidAmount}
          className={`w-[90%] py-4 rounded-2xl font-bold text-white shadow-xl transition-all ${
            isValidAmount ? "bg-[#00875A] shadow-emerald-100 active:scale-95" : "bg-gray-500 cursor-not-allowed"
          }`}
        >
          Lock Savings
        </button>
      </div>
    </div>
  );
}
